mapper.select:
SELECT CLAIM_NO as claimNo, MEMBER_ID as memberId, POLICY_NO as policyNo, CLAIM_AMOUNT as claimAmount, APPROVE_AMOUNT as approveAmount, CLAIM_STATUS as claimStatus, AGENT_ID as agentId, APPLY_TIME as applyTime, EXPIRY_TIME as expiryTime, SETTLE_TIME as settleTime, REMARK as remark, UPDATE_USER as updateUser, FILE_01_NAME as file01Name, FILE_01_PATH as file01Path, FILE_02_NAME as file02Name, FILE_02_PATH as file02Path FROM tb_claim
AND CLAIM_STATUS = #{status}
AND POLICY_NO LIKE CONCAT('%', #{policyNo}, '%')
AND DATE(APPLY_TIME) = #{applyDate}
ORDER BY APPLY_TIME DESC

