CLAIM_AMOUNT = #{claimAmount}, APPROVE_AMOUNT = #{approveAmount}, CLAIM_STATUS = #{claimStatus}, REMARK = #{remark}, UPDATE_USER = #{updateUser}, FILE_01_NAME = #{file01Name}, FILE_01_PATH = #{file01Path}, FILE_02_NAME = #{file02Name}, FILE_02_PATH = #{file02Path}, SETTLE_TIME = NOW(),
